INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$2095ce11-f054-4a05-bf84-a098d8800e83$tag$, $tag$2026011000027$tag$, $tag$Mário Jorge (5591988221632)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Educacao Crista Classica e quero mais informações.","time":"10/01/2026 15:21:50"},{"role":"client","text":"🌟 Boa tarde Mário Jorge! Que alegria ter você aqui com a gente! 🙌","time":"10/01/2026 15:21:51"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"10/01/2026 15:21:55"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"10/01/2026 15:21:58"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"10/01/2026 15:22:02"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"10/01/2026 15:22:08"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"10/01/2026 15:22:14"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"10/01/2026 15:22:15"},{"role":"client","text":"Sim, concordo","time":"10/01/2026 15:22:34"},{"role":"client","text":"✅ Obrigado, Mário Jorge! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"10/01/2026 15:22:35"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"10/01/2026 15:22:39"},{"role":"client","text":"Sistema de ensino \n Cidade Viva Education","time":"10/01/2026 15:23:15"},{"role":"client","text":"👋 Olá! Seja bem-vindo(a) ao *Cidade Viva Education*. Estou aqui para te ajudar! 😊","time":"10/01/2026 15:23:16"},{"role":"client","text":"Por favor, selecione no menu abaixo a melhor opção que se adequa à sua solicitação:","time":"10/01/2026 15:23:20"},{"role":"client","text":"Currículos disponíveis \n Quero conhecer os currículos disponíveis","time":"10/01/2026 15:23:33"},{"role":"client","text":"Temos 3 frentes principais. Veja e selecione abaixo qual delas você deseja conhecer:","time":"10/01/2026 15:23:37"},{"role":"client","text":"Voltar ao menu anterior","time":"10/01/2026 15:23:52"},{"role":"client","text":"Por favor, selecione no menu abaixo a melhor opção que se adequa à sua solicitação:","time":"10/01/2026 15:23:58"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"10/01/2026 15:24:15"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"10/01/2026 15:24:16"},{"role":"client","text":"Por favor, selecione no menu abaixo a melhor opção que se adequa à sua solicitação:","time":"10/01/2026 15:24:19"},{"role":"client","text":"Voltar ao menu anterior","time":"10/01/2026 15:24:28"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"10/01/2026 15:24:30"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"10/01/2026 15:24:39"},{"role":"client","text":"Olá! Mário Jorge!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"10/01/2026 15:24:40"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"10/01/2026 15:24:44"},{"role":"client","text":"Saber sobre os cursos","time":"10/01/2026 15:24:55"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"10/01/2026 15:24:59"},{"role":"client","text":"Pós-Graduação","time":"10/01/2026 15:25:08"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"10/01/2026 15:25:12"},{"role":"client","text":"Educação Cristã Clássica","time":"10/01/2026 15:25:21"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"10/01/2026 15:25:22"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"10/01/2026 15:25:26"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"10/01/2026 15:25:53"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"10/01/2026 15:25:54"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"10/01/2026 15:25:55"},{"role":"client","text":"krikrikri...um milhão de anos depois...","time":"11/01/2026 10:36:50"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"12/01/2026 08:19:14"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"12/01/2026 08:19:47","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"12/01/2026 08:20:07","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* *Educação Cristã Clássica* - Disciplinas do Curso:\n\nBase: Filosófica Teológica\nCosmovisão Cristã e Filosofia Reformada – Ms. Vinicius Pimentel\nFundamentos da Pedagogia Cristã – Ms. Igor Miguel\nA Paideia de Deus (Educação Pactual) – Ms. Rodrigo Brotto\n\nBase: Histórica Pedagógica Clássica&nbsp;\nHistória da Educação Clássica – Ms. Lucas Evangelista\nFundamentos Pedagógicos das Sete Artes Liberais – Ms. Rodrigo Brotto\nVerdade, Bondade e Beleza: A Formação do Imaginário – Ms. Raquel Van De Burgt\n\nBase: Metodológica Cristã Clássica\nAplicando o Trivium no Contexto Educacional – Ms. Renata Costa\nAprendendo a Ler Classicamente (Alfabetização Clássica) – Esp. Leandro Ribeiro\nDisciplina na Educação (Pastoreando o Coração da Criança) – Ms. Kenneth V. Trotter\nDesenvolvimento do Currículo - Kim Bedinfield\n\nObs: Professores sujeitos a alterações. ","time":"12/01/2026 08:20:14","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. Esta com condições especiais com 50% de desconto e as mensalidades está por R$ 239,58 \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para abril/2026.\n\n\n🎁 Cupom de Desconto ECC: *BOLSA50*\n📌 Realize sua matrícula no link: https://c95716.mannesoftprime.com.br/processo_seletivo/?PS=PROCESSO_SELETIVO_19\n\n\n*Mas lembrando que o desconto é de pontualidade  para pagamento até o dia 10 de cada mês, caso algum mês você pague fora desse período, naquele mês o valor vai ficar cheio. \n\n*Assim que fizer sua matricula e  efetuar o pagamento, me envia o comprovante de pagamento para eu poder da baixa no sistema.*","time":"12/01/2026 08:20:22","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Atendimento Finalizado!\n\nMário Jorge, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/01/2026 10:40:08"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"12/01/2026 10:40:09"},{"role":"client","text":"Mário Jorge, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"12/01/2026 10:55:10"}]$tag$, $tag$2026-01-10 15:21:50+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 4, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$c4951707-da70-494e-99e6-144644036dd5$tag$, $tag$2026011000014$tag$, $tag$Douglas Feitosa (5583998074082)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Direito e quero mais informações.","time":"10/01/2026 11:39:11"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"10/01/2026 11:39:12"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"10/01/2026 11:39:13"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"12/01/2026 08:33:01"},{"role":"agent","text":"*Karina Pimentel:* Olá Bom dia me chamo Karina Pimentel da Cidade Viva! \n","time":"12/01/2026 10:15:41","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nDouglas Feitosa, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"13/01/2026 09:08:28"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"15/01/2026 08:31:02"},{"role":"client","text":"Sua sessão expirou!","time":"15/01/2026 08:33:03"}]$tag$, $tag$2026-01-10 11:39:11+00$tag$, FALSE, FALSE, 6.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 10, 3, 2, 9, 1, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$9c1e0404-afe3-4c60-9daf-6a1adafe555e$tag$, $tag$2026011000016$tag$, $tag$Edriane N Lira (5583986774527)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia","time":"10/01/2026 12:33:29"},{"role":"client","text":"🌟 Boa tarde Edriane N Lira! Que alegria ter você aqui com a gente! 🙌","time":"10/01/2026 12:33:30"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"10/01/2026 12:33:34"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"10/01/2026 12:33:38"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"10/01/2026 12:33:45"},{"role":"client","text":"Como inserir o código para desconto no ato da inscrição? Não estou entendendo","time":"10/01/2026 12:34:12"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.\n","time":"10/01/2026 12:34:13"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"10/01/2026 12:34:13"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"10/01/2026 12:35:46"},{"role":"client","text":"Olá! Edriane N Lira!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"10/01/2026 12:35:47"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"10/01/2026 12:35:51"},{"role":"client","text":"Falar com um atendente","time":"10/01/2026 12:36:11"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"10/01/2026 12:36:12"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"10/01/2026 12:36:13"},{"role":"client","text":"Que código é esse para concluir a inscrição","time":"10/01/2026 12:40:22"},{"role":"client","text":"?","time":"10/01/2026 12:40:29"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"12/01/2026 08:33:10"},{"role":"agent","text":"*Karina Pimentel:* Olá Bom dia me chamo Karina Pimentel da Cidade Viva! \n","time":"12/01/2026 10:05:14","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Boa tarde","time":"12/01/2026 14:03:45"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!","time":"13/01/2026 09:19:52","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Como podemos lhe ajudar, Sra Edrianr?","time":"13/01/2026 09:20:03","feedback":"⚠️ Pergunta Genérica: Evite perguntas que podem ser respondidas com \"não\". Tente: \"Qual sua maior motivação para estudar hoje?\""},{"role":"client","text":"Não estou conseguindo finalizar minha matrícula na pós porque pede para entrar em contato com vocês 👇","time":"13/01/2026 09:21:09"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/696638d3956457252e0e8e01)","time":"13/01/2026 09:21:39"},{"role":"client","text":"Só não sei o por quê","time":"13/01/2026 09:21:50"},{"role":"agent","text":"*Karina Pimentel:* Vou lhe transferir na Secretaria ok!","time":"13/01/2026 09:30:40","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Deus abençoe!","time":"13/01/2026 09:31:14","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Karina Pimentel transferiu o atendimento para a equipe FICV - SECRETARIA","time":"13/01/2026 09:31:24"},{"role":"client","text":"Idem","time":"13/01/2026 09:31:52"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Tyago Mendes","time":"13/01/2026 13:32:12"},{"role":"client","text":"*Tyago Mendes:* Boa tarde, senhora","time":"13/01/2026 13:32:39"},{"role":"client","text":"*Tyago Mendes:* qual a pós que a senhora tem interesse?","time":"13/01/2026 13:32:53"},{"role":"client","text":"*Tyago Mendes:* e a senhora recebeu algum cupom de desconto?","time":"13/01/2026 13:33:09"},{"role":"client","text":"Aguardando enviar segundo previsto. Vai para o email é?","time":"13/01/2026 13:34:57"},{"role":"client","text":"*Tyago Mendes:* a senhora não conversou com ninguém do nosso comercial?","time":"13/01/2026 13:39:05"},{"role":"client","text":"*Tyago Mendes:* Vou lhe transferir para elas lhe apresentar os valores e o curso","time":"13/01/2026 13:39:57"},{"role":"client","text":"Tyago Mendes transferiu o atendimento para a equipe FICV - COMERCIAL","time":"13/01/2026 13:40:05"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"13/01/2026 13:40:14"},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!","time":"13/01/2026 13:40:42","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Conversei com tanta gente que nem sei dizer direito pois faz uns 3 dias que tento resolver 🤭","time":"13/01/2026 13:40:45"},{"role":"client","text":"Já falei e estou aguardando o desconto para finalizar a matrícula","time":"13/01/2026 13:41:51"},{"role":"agent","text":"*Karina Pimentel:* Vamos resolver já!","time":"13/01/2026 13:50:11","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Fez a inscrição já?","time":"13/01/2026 13:50:27","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Karina Pimentel:* Qual nome completo por gentileza?","time":"13/01/2026 13:50:47","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Não consigo finalizar porque pede número de cupom de desconto e ainda fala para entrar em contato com a secretaria: 👇","time":"13/01/2026 13:52:07"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/696678467c4243ede20449e7)","time":"13/01/2026 13:52:22"},{"role":"agent","text":"*Karina Pimentel:* Qual desconto que foi ofertado?","time":"13/01/2026 13:54:21","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Espero que não seja o mesmo equívoco de antes já segundo Víctor do financeiro resolvido: estava constando uma pendência de uma pós que nem me escrevi. 🤔","time":"13/01/2026 13:54:27"},{"role":"agent","text":"*Karina Pimentel:* Pode ser algum cadastro que ficou pendente e apresenta esse erro!","time":"13/01/2026 13:54:59","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Para ex- alunos de teologia. Vou olhar lá nas conversas.","time":"13/01/2026 13:55:11"},{"role":"client","text":"Meu nome: Edriane do Nascimento Lira","time":"13/01/2026 13:55:28"},{"role":"client","text":"O único cadastro que está pendente é a tentativa de concluir a matrícula na pós de Novo Testamento: Faz 8 dias que fiz tipo uma simulação","time":"13/01/2026 13:56:54"},{"role":"agent","text":"*Karina Pimentel:* Certo!","time":"13/01/2026 14:40:16","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Vou fazer um teste aqui ok!","time":"13/01/2026 14:40:27","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Um minuto por gentileza!","time":"13/01/2026 14:40:33","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* 🎁 Cupom de Desconto Novo Testamento: *BOLSA50*\n\n📌 Realize sua matrícula no link: bit.ly/InscricaoPosNT2024\n\n✅ Assim que você preencher os seus dados, o sistema disponibilizará o seu contrato para aceitação e o pagamento da primeira parcela, que pode ser feito por cartão ou boleto.","time":"13/01/2026 14:42:50","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Vamos tentar realizar uma nova inscrição?","time":"13/01/2026 14:43:08","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Onde localizar o código do desconto que está pedindo?","time":"13/01/2026 15:09:46"},{"role":"client","text":"Que Cupom Voucher é esse?","time":"13/01/2026 15:10:53"},{"role":"client","text":"Sem esse cupom não recebo o desconto? So quero confirmar matrícula se tiver o desconto anunciado","time":"13/01/2026 15:15:00"},{"role":"agent","text":"*Karina Pimentel:* Sim, BOLSA50.","time":"13/01/2026 15:33:49","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Caso não saia o desconto eu aplico internamente! ","time":"13/01/2026 15:34:19","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"No contrato ainda esta o valor fechado, não cita os 50%  nem o desconto  para quem pagar até o 10° dia. E agora?","time":"13/01/2026 15:47:16"},{"role":"agent","text":"*Karina Pimentel:* No contrato fala da pontualidade de pagamento. Que seria realizando os pagamentos até o dia 10 de todo mês, os descontos serão mantidos!","time":"13/01/2026 15:49:34","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Então esse desconto ê o de 50% certo? Outra dúvida:  não ha taxa de matricula. Então que boleto ê esse que o sistema quer gerar? E referente aos meses que antecedem o início das aulas tendo em vista que so iniciam em abril?","time":"13/01/2026 16:20:44"},{"role":"agent","text":"*Karina Pimentel:* Isso desconto de 50%, durante todo curso!","time":"13/01/2026 16:25:47","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"A pós inicia em abril e mesmo assim pagamos pelos meses que não faz parte do curso? Preciso entender melhor já que a matricula não é  paga' já  que o dia 10 passou e ja que o curso tem  inicio em abril","time":"13/01/2026 16:26:01"},{"role":"agent","text":"*Karina Pimentel:* Todo mês ficará disponível na Plataforma do aluno o seu boleto!","time":"13/01/2026 16:26:16","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Realizando o seu pagamento hoje, vai referir a sua primeira mensalidade das 16.","time":"13/01/2026 16:27:02","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Começo pagando abril certo?","time":"13/01/2026 16:27:10"},{"role":"agent","text":"*Karina Pimentel:* Próxima a ser paga será em Abril!","time":"13/01/2026 16:27:21","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Não cobramos a taxa de inscrição, será abatido na sua primeira mensalidade!","time":"13/01/2026 16:27:50","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"client","text":"Com o desconto ou sem  tendo em vista que hoje é dia 13?","time":"13/01/2026 16:29:11"},{"role":"agent","text":"*Karina Pimentel:* Com desconto!","time":"13/01/2026 16:29:37","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*  \n Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"14/01/2026 08:18:11","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nEdriane N Lira, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"14/01/2026 08:18:14"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"14/01/2026 08:18:15"},{"role":"client","text":"Edriane N Lira, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"14/01/2026 08:33:16"}]$tag$, $tag$2026-01-10 12:33:29+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 31, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$43b35d92-4ed8-4f9c-911c-934afca6918a$tag$, $tag$2026011000018$tag$, $tag$Thiago Mendes (5581984709009)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Ola","time":"10/01/2026 12:42:32"},{"role":"client","text":"🌟 Boa tarde Thiago Mendes! Que alegria ter você aqui com a gente! 🙌","time":"10/01/2026 12:42:32"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"10/01/2026 12:42:37"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"10/01/2026 12:42:41"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"10/01/2026 12:42:45"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"10/01/2026 12:42:51"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"10/01/2026 12:42:57"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"10/01/2026 12:42:58"},{"role":"client","text":"Sim, concordo","time":"10/01/2026 12:43:25"},{