INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$5a9c9e01-6e2e-4d8f-afe3-25ceaf4cadab$tag$, $tag$2026011400004$tag$, $tag$dux (5592982860149)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"14/01/2026 02:48:33"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"14/01/2026 02:48:34"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"14/01/2026 02:48:35"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"14/01/2026 08:04:55"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"14/01/2026 08:05:09","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A nossa Graduação em Teologia EAD é Bacharelado reconhecido pelo MEC ( bit.ly/3LlEgJS ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n","time":"14/01/2026 08:05:17","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Teologia bit.ly/3xljQgl","time":"14/01/2026 08:05:21","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"14/01/2026 08:05:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"14/01/2026 08:05:36","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\ndux, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"15/01/2026 08:25:27"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"17/01/2026 08:02:55"},{"role":"client","text":"Sua sessão expirou!","time":"17/01/2026 08:04:57"}]$tag$, $tag$2026-01-14 02:48:33+00$tag$, FALSE, FALSE, 5.8, $tag$2026-03-01 16:46:57.607947+00$tag$, 5, 10, 3, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$8f26fed1-a2aa-4ce1-a8e6-fe6658455b8e$tag$, $tag$2026011400008$tag$, $tag$Stephanne carvalho (5583996232209)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Direito e quero mais informações.","time":"14/01/2026 06:10:57"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"14/01/2026 06:10:58"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"14/01/2026 06:10:59"},{"role":"client","text":"Ok, combinado","time":"14/01/2026 06:11:23"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"14/01/2026 08:05:38"},{"role":"agent","text":"*Thayanne Sales:* Vou lhe enviar as informações sobre o curso","time":"14/01/2026 08:05:47","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Joia","time":"14/01/2026 08:05:57"},{"role":"agent","text":"*Thayanne Sales:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"14/01/2026 08:06:03","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Direito *bit.ly/3SpepqX*","time":"14/01/2026 08:06:08","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"14/01/2026 08:06:15","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"14/01/2026 08:06:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nStephanne carvalho, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"15/01/2026 08:25:34"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"17/01/2026 08:03:58"},{"role":"client","text":"Sua sessão expirou!","time":"17/01/2026 08:05:59"}]$tag$, $tag$2026-01-14 06:10:57+00$tag$, FALSE, FALSE, 5.8, $tag$2026-03-01 16:46:57.607947+00$tag$, 5, 10, 3, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$2060dd57-7e18-48f3-a789-59d48c73b22d$tag$, $tag$2026011400067$tag$, $tag$Rodrigo Lima GonÃ§alves (5516982521099)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Sim, concordo","time":"14/01/2026 11:20:03"},{"role":"client","text":"🌟 Bom dia Rodrigo Lima GonÃ§alves! Que alegria ter você aqui com a gente! 🙌","time":"14/01/2026 11:20:04"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"14/01/2026 11:20:08"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"14/01/2026 11:20:13"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"14/01/2026 11:20:18"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"14/01/2026 11:20:24"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"14/01/2026 11:20:30"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"14/01/2026 11:20:31"},{"role":"client","text":"Sim, concordo","time":"14/01/2026 11:21:34"},{"role":"client","text":"✅ Obrigado, Rodrigo Lima GonÃ§alves! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"14/01/2026 11:21:36"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"14/01/2026 11:21:40"},{"role":"client","text":"Fundação Cidade Viva","time":"14/01/2026 11:25:24"},{"role":"client","text":"Bom dia, Rodrigo Lima GonÃ§alves! 🙌 Obrigado(a) por entrar em contato com a Fundação Cidade Viva.","time":"14/01/2026 11:25:25"},{"role":"client","text":"Selecione a opção abaixo para o que deseja:","time":"14/01/2026 11:25:29"},{"role":"client","text":"Quero ajudar","time":"14/01/2026 11:25:43"},{"role":"client","text":"Ótimo, Rodrigo Lima GonÃ§alves! 😊 É uma alegria ter você com a gente nessa missão de ajudar!","time":"14/01/2026 11:25:44"},{"role":"client","text":"Por favor, selecione no menu abaixo a opção para nos contar como você deseja contribuir:","time":"14/01/2026 11:25:48"},{"role":"client","text":"Voltar ao menu anterior","time":"14/01/2026 11:26:04"},{"role":"client","text":"Selecione a opção abaixo para o que deseja:","time":"14/01/2026 11:26:09"},{"role":"client","text":"Voltar ao menu anterior","time":"14/01/2026 11:26:21"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"14/01/2026 11:26:22"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"14/01/2026 11:26:33"},{"role":"client","text":"Olá! Rodrigo Lima GonÃ§alves!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"14/01/2026 11:26:34"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"14/01/2026 11:26:38"},{"role":"client","text":"Saber sobre os cursos","time":"14/01/2026 11:26:52"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"14/01/2026 11:26:56"},{"role":"client","text":"Pós-Graduação","time":"14/01/2026 11:27:16"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"14/01/2026 11:27:20"},{"role":"client","text":"Liderança Cristã","time":"14/01/2026 11:27:39"},{"role":"client","text":"Lidere com sabedoria, integridade e propósito.\n 🧭 Curso voltado para líderes de igrejas, ministérios e organizações cristãs\n 🌍 Temas como discipulado, liderança servidora e gestão de equipes\n 📅 Ainda dá tempo de começar este semestre!\n","time":"14/01/2026 11:27:40"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"14/01/2026 11:27:44"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"14/01/2026 11:28:03"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"14/01/2026 11:28:04"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"14/01/2026 11:38:19"},{"role":"client","text":"Karina, gostaria de saber sobre valores do curso de liderança e se para pastores tem algum desconto.","time":"14/01/2026 11:46:13"},{"role":"client","text":"Também saber como é disponibilizado o material usado em cada matéria? PDF?","time":"14/01/2026 11:47:11"},{"role":"agent","text":"*Karina Pimentel:* \n *Pós-graduação em Liderança Cristã*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO E CARGA HORÁRIA\nO curso tem duração de 16 meses, com carga horária de 400h.\n\nDISCIPLINAS\nContamos com um total de 10 disciplinas.\n\nAULAS E AVALIAÇÕES\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas. As avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigatoriedade de TCC.","time":"14/01/2026 11:49:23","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Liderança Cristã está em 16 mensalidades de *R$ 359,37.*\n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril.","time":"14/01/2026 11:50:41","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 70% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 107,81.\nVamos garantir a sua vaga? 😊","time":"14/01/2026 11:51:29","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Nossa o preço está bom mesmo!!! A forma de pagamento é somente no cartão? Tem o pagamento recorrente? Pergunto porque nesse mês as coisas apertam devido a tantos impostos e escola das filhas!!! Aí vou analisar o que posso estar fazendo!!","time":"14/01/2026 11:54:48"},{"role":"agent","text":"*Karina Pimentel:* Pix, boleto ou cartão?","time":"14/01/2026 11:57:56","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:*      Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"15/01/2026 11:31:19","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nRodrigo Lima GonÃ§alves, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"15/01/2026 11:31:20"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"15/01/2026 11:31:21"},{"role":"client","text":"Rodrigo Lima GonÃ§alves, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"15/01/2026 11:46:21"}]$tag$, $tag$2026-01-14 11:20:03+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$8ac6dccb-7a93-4aa9-b8b7-ef3ab7b461ce$tag$, $tag$2026011400073$tag$, $tag$Elana Mirlla (5584998085240)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Sim, concordo","time":"14/01/2026 11:42:31"},{"role":"client","text":"🌟 Bom dia Elana Mirlla! Que alegria ter você aqui com a gente! 🙌","time":"14/01/2026 11:42:32"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"14/01/2026 11:42:36"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"14/01/2026 11:42:39"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"14/01/2026 11:42:44"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"14/01/2026 11:42:49"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"14/01/2026 11:42:55"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"14/01/2026 11:42:56"},{"role":"client","text":"Sim, concordo","time":"14/01/2026 11:44:51"},{"role":"client","text":"✅ Obrigado, Elana Mirlla! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"14/01/2026 11:44:52"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"14/01/2026 11:44:56"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"14/01/2026 11:45:19"},{"role":"client","text":"Olá! Elana Mirlla!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"14/01/2026 11:45:20"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"14/01/2026 11:45:24"},{"role":"client","text":"Saber sobre os cursos","time":"14/01/2026 11:46:12"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"14/01/2026 11:46:16"},{"role":"client","text":"Pós-Graduação","time":"14/01/2026 11:46:47"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"14/01/2026 11:46:51"},{"role":"client","text":"Educação Cristã Clássica","time":"14/01/2026 11:49:12"},{"role":"client","text":"Formação exclusiva para educadores e líderes que desejam ensinar com base na tradição cristã clássica.\n\n 📚 Cosmovisão cristã sólida\n 📌 Leituras fundamentais do pensamento ocidental\n 🧭 Formação para escolas cristãs ou ministérios educacionais\n 🗓️ Matrículas abertas para agosto","time":"14/01/2026 11:49:13"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"14/01/2026 11:49:18"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"14/01/2026 11:49:47"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"14/01/2026 11:49:48"},{"role":"client","text":"Ok","time":"14/01/2026 11:53:04"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"14/01/2026 11:55:42"},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.\n","time":"14/01/2026 11:56:11","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"14/01/2026 11:56:18","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"14/01/2026 11:56:26","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Quem são os professores?🙂","time":"14/01/2026 12:28:04"},{"role":"agent","text":"*Karina Pimentel:* *Educação Cristã Clássica* - Disciplinas do Curso:\n\nBase: Filosófica Teológica\nCosmovisão Cristã e Filosofia Reformada – Ms. Vinicius Pimentel\nFundamentos da Pedagogia Cristã – Ms. Igor Miguel\nA Paideia de Deus (Educação Pactual) – Ms. Rodrigo Brotto\n\nBase: Histórica Pedagógica Clássica&nbsp;\nHistória da Educação Clássica – Ms. Lucas Evangelista\nFundamentos Pedagógicos das Sete Artes Liberais – Ms. Rodrigo Brotto\nVerdade, Bondade e Beleza: A Formação do Imaginário – Ms. Raquel Van De Burgt\n\nBase: Metodológica Cristã Clássica\nAplicando o Trivium no Contexto Educacional – Ms. Renata Costa\nAprendendo a Ler Classicamente (Alfabetização Clássica) – Esp. Leandro Ribeiro\nDisciplina na Educação (Pastoreando o Coração da Criança) – Ms. Kenneth V. Trotter\nDesenvolvimento do Currículo - Kim Bedinfield\n\nObs: Professores sujeitos a alterações. ","time":"14/01/2026 13:42:10","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Bom dia! Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"15/01/2026 11:41:00","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nElana Mirlla, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"15/01/2026 11:41:03"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"15/01/2026 11:41:04"},{"role":"client","text":"Elana Mirlla, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"15/01/2026 11:56:05"}]$tag$, $tag$2026-01-14 11:42:31+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
